import json
import os
from typing import Any, Dict, List, Optional

import boto3


class SQSPublisher:
    def __init__(
        self,
        queue_url: str,
        region_name: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        aws_session_token: Optional[str] = None,
    ) -> None:
        self.queue_url = queue_url
        self.sqs = boto3.client(
            "sqs",
            region_name=region_name or os.getenv("AWS_REGION") or os.getenv("AWS_DEFAULT_REGION"),
            aws_access_key_id=aws_access_key_id,
            aws_secret_access_key=aws_secret_access_key,
            aws_session_token=aws_session_token,
        )

    def publish_user_data(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        if not isinstance(user_data, dict):
            raise TypeError("user_data must be a dict")

        body = json.dumps(user_data, ensure_ascii=False, separators=(",", ":"))
        return self.sqs.send_message(
            QueueUrl=self.queue_url,
            MessageBody=body,
        )

    def publish_batch(self, messages: List[Dict[str, Any]]) -> Dict[str, Any]:
        if not isinstance(messages, list):
            raise TypeError("messages must be a list of dicts")

        entries = []
        for i, msg in enumerate(messages):
            if not isinstance(msg, dict):
                raise TypeError("each message must be a dict")
            entries.append(
                {
                    "Id": str(i),
                    "MessageBody": json.dumps(msg, ensure_ascii=False, separators=(",", ":")),
                }
            )

        if not entries:
            return {"Successful": [], "Failed": []}

        return self.sqs.send_message_batch(
            QueueUrl=self.queue_url,
            Entries=entries,
        )


